from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Produce a more robust phrasing for nationality
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "is from the United States"
            elif low_obj.startswith("the "):
                return f"is from {obj}"
            else:
                return f"is {obj}"
        if p == "occupation":
            # Use a more natural verb for astronauts' roles
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # For mission subjects, express role succinctly
            return f"commander {obj}"
        if p == "backuppilot":
            # Phrase the backup pilot relation from the mission's perspective
            return f"{obj} was the backup pilot of {subj}"
        if p == "crewmembers":
            return f"crew member {obj}"
        if p == "leader":
            # Express leadership as a property of the entity
            return f"{subj} is led by {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    # Build mission role mappings to enable richer sentences
    mission_roles = {}
    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        if pred in ("commander", "backuppilot", "crewmembers"):
            role_dict = mission_roles.setdefault(t.subject, {"commander": None, "backupPilot": None, "crewMembers": []})
            if pred == "commander":
                role_dict["commander"] = t.object
            elif pred == "backuppilot":
                role_dict["backupPilot"] = t.object
            elif pred == "crewmembers":
                role_dict["crewMembers"].append(t.object)

    sentences = []
    for subj, items in groups.items():
        # Special handling for mission subjects that have role information
        if subj in mission_roles:
            roles = mission_roles[subj]
            role_parts = []
            if roles["commander"]:
                role_parts.append(f"commanded by {roles['commander']}")
            if roles["backupPilot"]:
                role_parts.append(f"with backup pilot {roles['backupPilot']}")
            if roles["crewMembers"]:
                crew_list = ", ".join(roles["crewMembers"])
                role_parts.append(f"and crew members {crew_list}")
            role_sentence = f"{subj} was " + ", ".join(role_parts) + "."
            # Process any additional predicates for the mission (e.g., operator)
            other_items = [t for t in items if t.predicate.lower().replace(" ", "") not in ("commander", "backuppilot", "crewmembers")]
            if other_items:
                extra_desc = [phrase(subj, t.predicate, t.object) for t in other_items]
                role_sentence = role_sentence.rstrip(".") + ", " + ", ".join(extra_desc) + "."
            sentences.append(role_sentence)
            continue

        subject_phrase = subj
        descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not descriptors:
            sentences.append(f"{subject_phrase}.")
            continue
        if len(descriptors) == 1:
            sent = f"{subject_phrase} {descriptors[0]}."
        else:
            body = ", ".join(descriptors[:-1])
            sent = f"{subject_phrase} {body}, and {descriptors[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

